#pragma once
#include <stddef.h>
#include <stdint.h>
#include <ship_data_model.hpp>
#include <nmea0183.hpp>
namespace signalk_mini{struct ModelChange{ship_data_model::FieldId field;uint16_t source_id;uint64_t timestamp_us;uint64_t sequence;};template<size_t N>class ModelChangeQueue{ModelChange q_[N];size_t h_=0,t_=0,c_=0;public:bool push(ModelChange m){if(c_==N){t_=(t_+1)%N;--c_;}q_[h_]=m;h_=(h_+1)%N;++c_;return true;}bool pop(ModelChange&m){if(!c_)return false;m=q_[t_];t_=(t_+1)%N;--c_;return true;}size_t size()const{return c_;}};template<typename Real,size_t N=128>class ModelStore{ship_data_model::DataModel<Real> model_{};ModelChangeQueue<N> changes_{};uint64_t seq_=0;public:ship_data_model::DataModel<Real>&model(){return model_;}ModelChangeQueue<N>&changes(){return changes_;}uint64_t sequence()const{return seq_;}void mark_changed(ship_data_model::FieldId f,uint16_t s,uint64_t now){changes_.push({f,s,now,++seq_});}};template<typename Real>class Nmea0183Input{ModelStore<Real>&s_;public:explicit Nmea0183Input(ModelStore<Real>&s):s_(s){}nmea0183::Status feed_line(const char*line,uint16_t src,uint64_t now){return nmea0183::apply_sentence<Real>(line,s_.model(),s_,src,now);}};template<typename Real>struct SignalKMappedValue{const char*path=nullptr;Real number{};};template<typename Real>class SignalKMapper{public:bool map_change(ship_data_model::DataModel<Real>&m,const ModelChange&c,SignalKMappedValue<Real>&o){using F=ship_data_model::FieldId;switch(c.field){case F::NavigationSogMps:o.path="navigation.speedOverGround";o.number=m.navigation.sog_mps.value;return true;case F::NavigationCogDeg:o.path="navigation.courseOverGroundTrue";o.number=nmea0183::deg_to_rad<Real>(m.navigation.cog_deg.value);return true;case F::NavigationHeadingTrueDeg:o.path="navigation.headingTrue";o.number=nmea0183::deg_to_rad<Real>(m.navigation.heading_true_deg.value);return true;case F::WindApparentAngleDeg:o.path="environment.wind.angleApparent";o.number=nmea0183::deg_to_rad<Real>(m.wind.apparent_angle_deg.value);return true;case F::WindApparentSpeedMps:o.path="environment.wind.speedApparent";o.number=m.wind.apparent_speed_mps.value;return true;case F::WaterDepthBelowTransducerM:o.path="environment.depth.belowTransducer";o.number=m.water.depth_below_transducer_m.value;return true;default:return false;}}};}
